mapper.select:
select TDSI.ID,TDSI.ID "shipVoyageItemId",TDS.id SHIP_VOYAGE_ID ,tds.SHIP_NAME||'_'||TDSI.VOYAGE SHIP_NAME,TDSI.TRADE_TYPE,TDSI.IMP_EXP,TDSI.LOAD_UNLOAD, TDS.SHIP_STATUS_CODE,TDS.SHIP_STATUS_NAME, TDSI.IS_ADJUST status,TDS.SCN SCN,TDSI.WORK_END_TIME, DECODE(TDSI.IS_ADJUST,'20','机械调整','未调整') statusLabel, DECODE(TDSI.IS_ADJUST_LABOR,'20','人员调整','未调整') statusLaborLabel, (select TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TO_CHAR(BERTH_NAME) || ',') ORDER BY BERTH_NAME) AS CLOB), ','), '([^,]+)(,\1)+', '\1')) from T_DIS_SHIP_DYNAMIC where SHIPVOYAGE_ID = TDS.ID group by SHIPVOYAGE_ID ) BERTH_NAME, TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TO_CHAR(TBCI.CARGO_NAME) || ',') ORDER BY TBCI.CARGO_NAME) AS CLOB), ','), '([^,]+)(,\1)+', '\1')) CARGO_NAME, MAX(tds.LEAVE_PORT_TIME) LEAVE_PORT_TIME, TDSI.IS_SHIP_CLEAR, TDSI.SHIP_PERSON_EXAMINE_BY, TDSI.SHIP_PERSON_EXAMINE_BY_NAME, TDSI.SHIP_PERSON_EXAMINE_TIME, TDSI.SHIP_MAC_EXAMINE_BY, TDSI.SHIP_MAC_EXAMINE_BY_NAME, TDSI.SHIP_MAC_EXAMINE_TIME from T_PRD_WORK_PLAN TPWP join T_BUS_TRUST TBT on TPWP.TRUST_ID = TBT.ID join T_DIS_SHIPVOYAGE_ITEM TDSI on TDSI.id = TBT.SHIPVOYAGE_ITEM_ID join T_DIS_SHIPVOYAGE TDS on TDS.id = TDSI.SHIPVOYAGE_ID join T_BUS_TRUST_CARGO TBTC on TBTC.TRUST_ID = TBT.ID join T_BUS_CARGO_INFO TBCI on TBCI.id = TBTC.CARGO_INFO_ID left join ( select TDSI1.ID SHIP_VOYAGE_ITEM_ID,TDSD.DYNAMIC_TYPE_CODE from T_DIS_SHIPVOYAGE TDS1 left join T_DIS_SHIPVOYAGE_ITEM TDSI1 on TDS1.id = TDSI1.SHIPVOYAGE_ID left join T_DIS_SHIP_DYNAMIC TDSD on TDSD.SHIPVOYAGE_ITEM_ID = TDSI1.ID
) TMP_DYNAMIC on TMP_DYNAMIC.SHIP_VOYAGE_ITEM_ID = TDSI.ID where TDSI.id is not null and TDS.DEL_FLAG ='0'
and TDSI.WORK_START_TIME>= #{startTime,jdbcType=TIMESTAMP}
and TDSI.WORK_START_TIME <= #{endTime,jdbcType=TIMESTAMP}
and TDSI.ID = #{shipVoyageItemId,jdbcType=BIGINT}
AND TDS.SHIP_STATUS_CODE = #{shipStatusCode,jdbcType=VARCHAR}
AND TDS.SHIP_NAME LIKE #{shipNameLike,jdbcType=VARCHAR}
AND TDSI.VOYAGE LIKE #{voyageLike,jdbcType=VARCHAR}
AND TDS.SCN LIKE #{scnLike,jdbcType=VARCHAR}
and TMP_DYNAMIC.SHIP_VOYAGE_ITEM_ID is not null
and TDSI.SHIP_PERSON_EXAMINE_BY is not null
and TDSI.SHIP_MAC_EXAMINE_BY is not null
and TMP_DYNAMIC.SHIP_VOYAGE_ITEM_ID is null
group by TDSI.ID ,TDS.ID,TDS.SCN,tds.SHIP_NAME,TDSI.VOYAGE,TDSI.TRADE_TYPE,TDSI.IS_ADJUST,TDSI.IS_ADJUST_LABOR, TDSI.IMP_EXP,TDSI.LOAD_UNLOAD,TDS.SHIP_STATUS_CODE,TDS.SHIP_STATUS_NAME,TDSI.WORK_END_TIME,TDSI.IS_SHIP_CLEAR, TDSI.SHIP_PERSON_EXAMINE_BY,TDSI.SHIP_PERSON_EXAMINE_BY_NAME,TDSI.SHIP_PERSON_EXAMINE_TIME,TDSI.SHIP_MAC_EXAMINE_BY,TDSI.SHIP_MAC_EXAMINE_BY_NAME,TDSI.SHIP_MAC_EXAMINE_TIME ORDER BY MAX(TDSI.WORK_END_TIME) DESC nulls last

select TPWTD.id, TPWTD.work_ticket_id, TPWTD.cargo_info_id, TPWTD.process_code, TPWTD.process_name, TPWTD.process_detail_code, MWP.PROCESS_NM process_detail_name, TPWTD.dept_id, TPWTD.dept_name, TPWTD.work_date, TPWTD.quantity, TPWTD.ton, TPWTD.remark, TPWTD.allot_type, TPWTD.work_position_code, TPWTD.work_position_name, TPWTD.WORK_DATE, TPWTD.CLASS_NAME, TPWTD.CLASS_CODE, TPWP.id work_plan_id, TPWT.COMPANY_ID, TPWT.COMPANY_NAME, TBT.ID TRUST_ID, TBT.TRUST_NO, to_date(to_char(TPWP.work_date,'yyyy-MM'),'yyyy-MM') work_date_check, (select TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TO_CHAR(EQUIPMENT_TYPE_NAME) || ',') ORDER BY ID) AS CLOB), ','), '([^,]+)(,\1)+', '\1')) from T_PRD_WORK_TICKET_EQUIPMENT where WORK_TICKET_DETAIL_ID = TPWTD.ID group by WORK_TICKET_DETAIL_ID ) EQUIPMENT_TYPE_NAME, (select TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TO_CHAR(EQUIPMENT_NO) || ',') ORDER BY ID) AS CLOB), ','), '([^,]+)(,\1)+', '\1')) from T_PRD_WORK_TICKET_EQUIPMENT where WORK_TICKET_DETAIL_ID = TPWTD.ID group by WORK_TICKET_DETAIL_ID ) EQUIPMENT_NO
from T_DIS_SHIPVOYAGE_ITEM TDSI join T_DIS_SHIPVOYAGE TDS on TDS.id = TDSI.SHIPVOYAGE_ID join T_BUS_TRUST TBT on (TBT.SHIPVOYAGE_ITEM_ID = TDSI.ID and TBT.TYPE in ('卸船','装船')) join T_PRD_WORK_PLAN TPWP on TPWP.TRUST_ID = TBT.ID join T_PRD_WORK_TICKET TPWT on TPWT.WORK_PLAN_ID = TPWP.ID join T_PRD_WORK_TICKET_DETAIL TPWTD on TPWTD.WORK_TICKET_ID = TPWT.ID left join M_WORK_PROCESS MWP on MWP.PROCESS_CD = TPWTD.PROCESS_DETAIL_CODE
where TPWTD.DEPT_NAME!='固机队' and TPWTD.ALLOT_TYPE = #{allotType,jdbcType=VARCHAR} and TDSI.ID = #{shipVoyageItemId,jdbcType=BIGINT}

mapper.update:
BEGIN
UPDATE T_PRD_WORK_TICKET_DETAIL SET QUANTITY = #{item.quantity,jdbcType=INTEGER}, TON = #{item.ton,jdbcType=DECIMAL}, remark = #{item.remark,jdbcType=VARCHAR}, UPDATE_BY = #{item.updateBy, jdbcType=BIGINT}, UPDATE_BY_NAME = #{item.updateByName, jdbcType=BIGINT}, UPDATE_TIME = #{item.now,jdbcType=TIMESTAMP} WHERE id = #{item.id}
;
END;

mapper.select:
select TPDS.DEPT_ID, TPDS.DEPT_NAME, TPDS.EQUIPMENT_ID, MM.MAC_CODE EQUIPMENT_NO, MM.MAC_NAME EQUIPMENT_NAME, MMT.MAC_TYPE_CODE EQUIPMENT_TYPE_CODE, MMT.ID EQUIPMENT_TYPE_ID, TPDS.NUMBER_COUNT, MMT.mac_type_name EQUIPMENT_TYPE_NAME, TPDS.DEPT_PARENT_ID, TPDS.DEPT_PARENT_NAME, SUB_PROCESS_CODE, SUB_PROCESS_NAME, WORK_POSITION_CODE, WORK_POSITION_NAME, MWP.IS_TALLY_COURSE from T_PRD_DISPATCH_SECONDARY TPDS left join M_MACHINE MM on TPDS.EQUIPMENT_ID = MM.ID left join M_MACHINE_TYPE MMT on TPDS.EQUIPMENT_TYPE_ID = MMT.ID left join M_WORK_PROCESS MWP on MWP.PROCESS_CD = TPDS.SUB_PROCESS_CODE
TPDS.DISPATCH_TYPE = #{dispatchType} and TPDS.WORK_PLAN_ID =#{workPlanId,jdbcType=BIGINT}
and (TPDS.dept_name != '固机队' or not exists( select ID from ( select ID from SYS_DEPT where PARENT_ID != (select id from SYS_DEPT where DEPT_NAME = '固机队' ) ) tmp where TPDS.dept_ID = tmp.id ))

select TPWT.ID,TPWTD.WORK_TICKET_ID,TPWTD.CARGO_CODE,TPWTD.CARGO_NAME,TPWTD.ID ticket_detail_id, TPWTD.PROCESS_DETAIL_NAME,TPWTD.PROCESS_DETAIL_CODE,TPWTD.WORK_DATE,TPWTD.CLASS_NAME,TPWTD.TON from T_PRD_WORK_TICKET TPWT left join T_PRD_WORK_TICKET_DETAIL TPWTD on TPWT.ID = TPWTD.WORK_TICKET_ID where TPWTD.ALLOT_TYPE = '1' and TPWTD.DEPT_NAME != '固机队' and exists( select * from (
select #{tmpId,jdbcType=BIGINT} as TMPID from dual
) a where a.TMPID = TPWT.ID )

select TPWT.ID,TPWTD.WORK_TICKET_ID,TPWTD.CARGO_CODE,TPWTD.CARGO_NAME,TPWTD.ID ticket_detail_id, TPWTD.PROCESS_DETAIL_NAME,TPWTD.PROCESS_DETAIL_CODE,TPWTD.WORK_DATE,TPWTD.CLASS_NAME,TPWTD.TON from T_PRD_WORK_TICKET TPWT left join T_PRD_WORK_TICKET_DETAIL TPWTD on TPWT.ID = TPWTD.WORK_TICKET_ID where TPWTD.ALLOT_TYPE = '1' and exists( select * from (
select #{tmpId,jdbcType=BIGINT} as TMPID from dual
) a where a.TMPID = TPWT.ID )

select TPWTD.ID ID,TPWT.ID WORK_TICKET_ID,TPWT.work_plan_id,TPWTD.PROCESS_DETAIL_CODE, TPWP.PROCESS_NAME,TPWP.PROCESS_CODE,TPWTD.ALLOT_TYPE, WORK_POSITION_CODE,WORK_POSITION_NAME,tpwp.COMPANY_NAME,tpwp.COMPANY_ID, TPWTD.DEPT_ID,TPWTD.DEPT_NAME, TPWP.WORK_DATE, to_date(to_char(TPWP.WORK_DATE,'yyyy-MM'),'yyyy-MM') work_date_check, case when TPWP.CLASS_CODE ='02' then '夜班' when TPWP.CLASS_CODE ='01' then '白班' end CLASS_NAME, TPWP.CLASS_CODE, TPWTD.TON, MWP.PROCESS_NM PROCESS_DETAIL_NAME, (select TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TO_CHAR(EQUIPMENT_TYPE_NAME) || ',') ORDER BY ID) AS CLOB), ','), '([^,]+)(,\1)+', '\1')) from T_PRD_WORK_TICKET_EQUIPMENT where WORK_TICKET_DETAIL_ID = TPWTD.ID group by WORK_TICKET_DETAIL_ID ) EQUIPMENT_TYPE_NAME, (select TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TO_CHAR(EQUIPMENT_NO) || ',') ORDER BY ID) AS CLOB), ','), '([^,]+)(,\1)+', '\1')) from T_PRD_WORK_TICKET_EQUIPMENT where WORK_TICKET_DETAIL_ID = TPWTD.ID group by WORK_TICKET_DETAIL_ID ) EQUIPMENT_NO from T_PRD_WORK_TICKET_DETAIL TPWTD left join T_PRD_WORK_TICKET TPWT on TPWTD.WORK_TICKET_ID = TPWT.ID left join T_PRD_WORK_PLAN TPWP on TPWT.WORK_PLAN_ID = TPWP.ID left join SYS_DEPT SD on SD.id = TPWTD.DEPT_ID left join M_WORK_PROCESS MWP on MWP.PROCESS_CD = TPWTD.PROCESS_DETAIL_CODE where TPWP.PLAN_TYPE = '4' and TPWP.SHIPVOYAGE_ITEM_ID = #{shipVoyageItemId,jdbcType=BIGINT}
and SD.IS_MACHINE = '1'
and SD.IS_LABOR = '1'
